const config = {
  "previewFeatures": [],
  "clientVersion": "7.5.0",
  "engineVersion": "280c870be64f457428992c43c1f6d557fab6e29e",
  "activeProvider": "postgresql",
  "inlineSchema": "// ═══════════════════════════════════════════════════════════════════════════════════════════\n//  RESQID — coreZ Technologies Pvt. Ltd.\n//  Database Schema v8.0 — ORCHESTRATOR READY\n//  Fixed: 2026-03-29\n// ═══════════════════════════════════════════════════════════════════════════════════════════\n// \n//  FIXES APPLIED (Orchestrator System Prompt v2.0 Audit):\n//  ─────────────────────────────────────────────────────────────────────────────────────────\n//  CRITICAL:\n//    [C1] Added DATABASE_URL to datasource block\n//    [C2] Created DashboardUserType enum + changed DashboardNotification.user_type to use it\n//\n//  HIGH:\n//    [H1] Added DashboardNotification FK relations to SchoolUser and SuperAdmin\n//    [H2] Removed dashboardNotifications relation from ParentUser\n//    [H3] Added Invoice.pdf_generated_at field for idempotency\n//    [H4] Created PipelineStatus + DesignStatus enums; updated Student fields\n//    [H5] Added CardOrder.pipeline_started_at + design_started_at timestamps\n//\n//  MEDIUM:\n//    [M1] Added ScanLog.dispatched_channels + failed_channels fields\n//    [M2] Renamed OtpLog → OtpAuditLog, removed otp_hash (now Redis-only)\n//    [M3] Removed Payment.provider field (offline payments)\n//    [M4] Added OrderStatusLog.actor_type field\n//    [M5] Added DashboardNotification composite index on (user_id, user_type)\n//\n//  LOW:\n//    [L1] Replaced CardOrderItem.qr_generated with pipeline_status enum\n//    [L2] Documented Student.token vs token_hash usage\n//\n// ═══════════════════════════════════════════════════════════════════════════════════════════\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================================\n// ENUMS (UPDATED)\n// =============================================================================\n\nenum UserStatus {\n  ACTIVE\n  SUSPENDED\n  DELETED\n}\n\nenum AppTheme {\n  LIGHT\n  DARK\n  SYSTEM\n}\n\nenum ProfileType {\n  STUDENT\n  ELDERLY\n  PET\n  INDIVIDUAL\n}\n\nenum SetupStage {\n  PENDING\n  BASIC\n  COMPLETE\n  VERIFIED\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n  PREFER_NOT_TO_SAY\n}\n\nenum BloodGroup {\n  A_POS\n  A_NEG\n  B_POS\n  B_NEG\n  AB_POS\n  AB_NEG\n  O_POS\n  O_NEG\n  UNKNOWN\n}\n\nenum TokenStatus {\n  UNASSIGNED\n  ISSUED\n  ACTIVE\n  INACTIVE\n  REVOKED\n  EXPIRED\n}\n\nenum SchoolRole {\n  ADMIN\n}\n\nenum ScanResult {\n  SUCCESS\n  INVALID\n  REVOKED\n  EXPIRED\n  INACTIVE\n  UNREGISTERED\n  ISSUED\n  RATE_LIMITED\n  ERROR\n}\n\nenum ScanPurpose {\n  QR_SCAN\n  MANUAL_LOOKUP\n  HONEYPOT\n}\n\nenum AnomalyType {\n  HIGH_FREQUENCY\n  MULTIPLE_LOCATIONS\n  SUSPICIOUS_IP\n  AFTER_HOURS\n  BULK_SCRAPING\n  HONEYPOT_TRIGGERED\n  REPEATED_FAILURE\n}\n\nenum AnomalySeverity {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum SubscriptionStatus {\n  TRIALING\n  ACTIVE\n  PAST_DUE\n  CANCELED\n  EXPIRED\n}\n\nenum PlanType {\n  FREE_PILOT\n  GOVT_STANDARD\n  PRIVATE_STANDARD\n  ENTERPRISE\n}\n\nenum OrderPaymentStatus {\n  UNPAID\n  PARTIALLY_PAID\n  FULLY_PAID\n  REFUNDED\n}\n\nenum PaymentStatus {\n  PENDING\n  SUCCESS\n  FAILED\n  REFUNDED\n}\n\nenum InvoiceCategory {\n  ORDER_INVOICE\n  RENEWAL_INVOICE\n}\n\nenum OrderInvoiceType {\n  PARTIAL\n  FINAL\n}\n\nenum RenewalInvoiceType {\n  RENEWAL\n}\n\nenum InvoiceStatus {\n  DRAFT\n  ISSUED\n  PAID\n  OVERDUE\n  CANCELLED\n}\n\nenum OrderType {\n  BLANK\n  PRE_DETAILS\n}\n\nenum OrderMode {\n  BULK\n  SINGLE\n}\n\nenum OrderChannel {\n  DASHBOARD\n  CALL\n}\n\nenum OrderStatus {\n  PENDING\n  PARTIAL_PAYMENT_CONFIRMED\n  PARTIAL_INVOICE_GENERATED\n  TOKEN_GENERATING\n  TOKEN_COMPLETE\n  DESIGN_GENERATING\n  DESIGN_COMPLETE\n  DESIGN_APPROVED\n  VENDOR_SENT\n  PRINTING\n  SHIPPED\n  DELIVERED\n  COMPLETED\n  CANCELLED\n  REFUNDED\n}\n\nenum OrderItemStatus {\n  PENDING\n  TOKEN_GENERATED\n  CARD_DESIGNED\n  PRINTED\n  SHIPPED\n  DELIVERED\n}\n\nenum ShipmentStatus {\n  PENDING\n  PICKUP_SCHEDULED\n  PICKED_UP\n  IN_TRANSIT\n  OUT_FOR_DELIVERY\n  DELIVERED\n  FAILED\n  RETURNED\n}\n\nenum TokenBatchStatus {\n  PENDING\n  PROCESSING\n  COMPLETE\n  PARTIAL\n  FAILED\n}\n\nenum SchoolType {\n  GOVERNMENT\n  PRIVATE\n  INTERNATIONAL\n  NGO\n}\n\nenum PricingTier {\n  GOVT_STANDARD\n  PRIVATE_STANDARD\n  ENTERPRISE\n  FREE_PILOT\n}\n\nenum PaymentMode {\n  BANK_TRANSFER\n  UPI\n  CHEQUE\n  CASH\n}\n\nenum VendorStatus {\n  ACTIVE\n  INACTIVE\n  BLACKLISTED\n}\n\nenum ShiprocketStatus {\n  PENDING\n  PICKUP_SCHEDULED\n  PICKED_UP\n  IN_TRANSIT\n  OUT_FOR_DELIVERY\n  DELIVERED\n  UNDELIVERED\n  CANCELLED\n  RTO_INITIATED\n  RTO_DELIVERED\n}\n\nenum PrintStatus {\n  PENDING\n  PRINTED\n  REPRINTED\n  FAILED\n}\n\nenum QrFormat {\n  PNG\n  SVG\n  PDF\n}\n\nenum QrType {\n  BLANK\n  PRE_DETAILS\n}\n\n// [C2] NEW ENUM: Dashboard user type for typed notifications\nenum DashboardUserType {\n  SUPER_ADMIN\n  SCHOOL_ADMIN\n}\n\nenum DashboardNotificationType {\n  ORDER_PLACED\n  ORDER_CONFIRMED\n  TOKEN_GENERATION_COMPLETE\n  DESIGN_READY_FOR_APPROVAL\n  CARD_DESIGN_READY\n  CARDS_SHIPPED\n  CARDS_DELIVERED\n  PARTIAL_INVOICE_GENERATED\n  INVOICE_GENERATED\n  PIPELINE_STALLED\n  DLQ_NEW_ENTRY\n  EMERGENCY_FIRED\n}\n\nenum NotificationChannel {\n  SMS\n  EMAIL\n  PUSH\n  WHATSAPP\n}\n\nenum NotificationStatus {\n  QUEUED\n  SENT\n  FAILED\n  SUPPRESSED\n}\n\nenum ActorType {\n  SUPER_ADMIN\n  ADMIN\n  PARENT_USER\n  SYSTEM\n}\n\nenum ProfileVisibility {\n  PUBLIC\n  MINIMAL\n  HIDDEN\n}\n\nenum LocationSource {\n  SCAN_TRIGGER\n  PARENT_APP\n  MANUAL\n}\n\nenum IpCaptureBasis {\n  LEGITIMATE_INTEREST\n  CONSENT\n  LEGAL_OBLIGATION\n}\n\nenum ParentEditType {\n  EMERGENCY_CONTACTS\n  EMERGENCY_PROFILE\n  STUDENT_NAME\n  STUDENT_PHOTO\n  PARENT_PHONE\n  PARENT_EMAIL\n  CARD_VISIBILITY\n  CARD_BLOCK\n  CARD_REPLACEMENT\n  NOTIFICATION_PREFS\n}\n\nenum OtpPurpose {\n  LOGIN\n  PHONE_VERIFY\n  CARD_BLOCK\n  CARD_REPLACEMENT\n  EMAIL_VERIFY\n  DEVICE_CHANGE\n  CHANGE_PIN\n}\n\nenum RateLimitIdentifierType {\n  IP\n  DEVICE\n  TOKEN\n}\n\nenum DevicePlatform {\n  IOS\n  ANDROID\n  WEB\n}\n\nenum DeviceLogoutReason {\n  NEW_DEVICE_LOGIN\n  MANUAL_LOGOUT\n  SESSION_EXPIRED\n  ADMIN_REVOKED\n  SUSPICIOUS_ACTIVITY\n}\n\nenum SessionRevokeReason {\n  NEW_DEVICE_LOGIN\n  MANUAL_LOGOUT\n  SESSION_EXPIRED\n  ADMIN_REVOKED\n  PASSWORD_CHANGED\n  PHONE_CHANGED\n}\n\nenum ScanType {\n  EMERGENCY\n  CHECK_IN\n  ATTENDANCE\n  OTHER\n}\n\n// =============================================================================\n// PIPELINE ENUMS\n// =============================================================================\n\nenum PipelineStepName {\n  CREATE\n  CONFIRM\n  PARTIAL_INVOICE\n  PARTIAL_PAYMENT\n  TOKEN_GENERATION\n  CARD_DESIGN\n  VENDOR_DISPATCH\n  PRINTING_START\n  PRINTING_DONE\n  SHIPMENT_CREATE\n  SHIPMENT_SHIPPED\n  DELIVERY\n  FINAL_INVOICE\n  FINAL_PAYMENT\n  CANCEL\n  REFUND\n}\n\nenum StepStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  PARTIAL_FAILED\n  SKIPPED\n}\n\nenum JobStatus {\n  QUEUED\n  RUNNING\n  COMPLETED\n  FAILED\n  RETRYING\n  DEAD\n}\n\n// [H4] NEW ENUMS: Pipeline and Design status tracking\nenum PipelineStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETE\n  FAILED\n}\n\nenum DesignStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETE\n  FAILED\n}\n\n// =============================================================================\n// SCHOOL\n// =============================================================================\n\nmodel School {\n  id                  String      @id @default(uuid())\n  name                String\n  address             String?\n  city                String?\n  state               String?\n  pincode             String?\n  country             String      @default(\"IN\")\n  code                String      @unique\n  serial_number       Int         @unique @default(autoincrement())\n  email               String?\n  phone               String?\n  logo_url            String?\n  timezone            String      @default(\"Asia/Kolkata\")\n  school_type         SchoolType  @default(PRIVATE)\n  pricing_tier        PricingTier @default(PRIVATE_STANDARD)\n  udise_code          String?     @unique\n  affiliation_num     String?\n  affiliated_board    String?\n  contract_signed_at  DateTime?\n  contract_expires_at DateTime?\n  onboarded_by        String?\n  onboarded_at        DateTime?\n  is_active           Boolean     @default(true)\n  created_at          DateTime    @default(now())\n  updated_at          DateTime    @updatedAt\n\n  apiKeys                ApiKey[]\n  auditLogs              AuditLog[]\n  cards                  Card[]\n  cardOrders             CardOrder[]\n  cardRenewals           CardRenewal[]\n  cardTemplate           CardTemplate?\n  dashboardNotifications DashboardNotification[]\n  featureFlags           SchoolFeatureFlag[]\n  invoices               Invoice[]\n  notifications          Notification[]\n  parentEditLogs         ParentEditLog[]\n  payments               Payment[]\n  scanLogs               ScanLog[]\n  locationEvents         LocationEvent[]\n  settings               SchoolSettings?\n  students               Student[]\n  subscriptions          Subscription[]\n  tokens                 Token[]\n  tokenBatches           TokenBatch[]\n  trustedScanZones       TrustedScanZone[]\n  users                  SchoolUser[]\n  webhooks               Webhook[]\n  qrAssets               QrAsset[]\n\n  @@index([code])\n  @@index([is_active])\n  @@index([serial_number])\n}\n\nmodel SchoolSettings {\n  id                         String            @id @default(uuid())\n  school_id                  String            @unique\n  allow_location             Boolean           @default(false)\n  allow_parent_edit          Boolean           @default(true)\n  scan_notifications_enabled Boolean           @default(true)\n  notify_on_every_scan       Boolean           @default(false)\n  scan_alert_cooldown_mins   Int               @default(60)\n  token_validity_months      Int               @default(12)\n  max_tokens_per_student     Int               @default(1)\n  default_profile_visibility ProfileVisibility @default(PUBLIC)\n  renewal_reminder_days      Int[]             @default([30, 15, 7, 1])\n  auto_deactivate_on_expiry  Boolean           @default(true)\n  school_hours_start         String            @default(\"08:00\")\n  school_hours_end           String            @default(\"17:00\")\n  school_days                Int[]             @default([1, 2, 3, 4, 5])\n  created_at                 DateTime          @default(now())\n  updated_at                 DateTime          @updatedAt\n  school                     School            @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([allow_location])\n}\n\n// =============================================================================\n// USERS\n// =============================================================================\n\nmodel SchoolUser {\n  id                     String                  @id @default(uuid())\n  school_id              String\n  email                  String                  @unique\n  password_hash          String\n  name                   String?\n  role                   SchoolRole              @default(ADMIN)\n  is_active              Boolean                 @default(true)\n  last_login_at          DateTime?\n  created_at             DateTime                @default(now())\n  updated_at             DateTime                @updatedAt\n  school                 School                  @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  sessions               Session[]\n  dashboardNotifications DashboardNotification[]\n\n  @@index([school_id])\n}\n\nmodel ParentUser {\n  id                 String                  @id @default(uuid())\n  email              String?                 @unique\n  phone              String                  @unique\n  phone_index        String?                 @unique\n  password_hash      String?\n  name               String?\n  avatar_url         String?\n  preferred_language String                  @default(\"en\")\n  preferred_theme    AppTheme                @default(SYSTEM)\n  is_phone_verified  Boolean                 @default(false)\n  is_email_verified  Boolean                 @default(false)\n  status             UserStatus              @default(ACTIVE)\n  last_login_at      DateTime?\n  deleted_at         DateTime?\n  created_at         DateTime                @default(now())\n  updated_at         DateTime                @updatedAt\n  children           ParentStudent[]\n  devices            ParentDevice[]\n  editLogs           ParentEditLog[]\n  notificationPrefs  ParentNotificationPref?\n  notifications      Notification[]\n  sessions           Session[]\n  deviceLoginLogs    DeviceLoginLog[]\n  // [H2] REMOVED: dashboardNotifications — parents use mobile app, not dashboard\n\n  @@index([phone_index])\n}\n\nmodel ParentDevice {\n  id            String              @id @default(uuid())\n  parent_id     String\n  device_token  String              @unique\n  platform      DevicePlatform\n  device_name   String?\n  device_model  String?\n  os_version    String?\n  app_version   String?\n  is_active     Boolean             @default(true)\n  last_seen_at  DateTime?\n  logged_out_at DateTime?\n  logout_reason DeviceLogoutReason?\n  created_at    DateTime            @default(now())\n  parent        ParentUser          @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_id, is_active])\n}\n\nmodel ParentNotificationPref {\n  id                        String     @id @default(uuid())\n  parent_id                 String     @unique\n  scan_notify_enabled       Boolean    @default(true)\n  scan_notify_push          Boolean    @default(true)\n  scan_notify_sms           Boolean    @default(false)\n  scan_notify_email         Boolean    @default(false)\n  anomaly_notify_enabled    Boolean    @default(true)\n  anomaly_notify_push       Boolean    @default(true)\n  anomaly_notify_sms        Boolean    @default(true)\n  anomaly_notify_email      Boolean    @default(true)\n  card_expiry_notify        Boolean    @default(true)\n  card_blocked_notify       Boolean    @default(true)\n  device_login_notify_email Boolean    @default(true)\n  account_change_notify     Boolean    @default(true)\n  quiet_hours_enabled       Boolean    @default(false)\n  quiet_hours_start         String?\n  quiet_hours_end           String?\n  created_at                DateTime   @default(now())\n  updated_at                DateTime   @updatedAt\n  parent                    ParentUser @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n}\n\nmodel SuperAdmin {\n  id                     String                  @id @default(uuid())\n  name                   String\n  email                  String                  @unique\n  password_hash          String\n  is_active              Boolean                 @default(true)\n  last_login_at          DateTime?\n  created_at             DateTime                @default(now())\n  updated_at             DateTime                @updatedAt\n  sessions               Session[]\n  dashboardNotifications DashboardNotification[]\n\n  @@index([email])\n}\n\n// =============================================================================\n// OTP - REDIS ONLY (Audit log only)\n// [M2] RENAMED: OtpLog → OtpAuditLog, removed otp_hash field\n// OTP verification now uses Redis only per Orchestrator Rule 2\n// =============================================================================\n\nmodel OtpAuditLog {\n  id           String     @id @default(uuid())\n  phone_index  String\n  purpose      OtpPurpose\n  attempts     Int        @default(0)\n  max_attempts Int        @default(5)\n  verified     Boolean    @default(false)\n  verified_at  DateTime?\n  expires_at   DateTime\n  invalidated  Boolean    @default(false)\n  msg91_req_id String?\n  ip_address   String?\n  created_at   DateTime   @default(now())\n\n  @@index([phone_index, purpose])\n  @@index([expires_at])\n}\n\n// =============================================================================\n// STUDENTS (UPDATED with pipeline fields)\n// =============================================================================\n\nmodel Student {\n  id               String      @id @default(uuid())\n  school_id        String?\n  profile_type     ProfileType @default(STUDENT)\n  setup_stage      SetupStage  @default(PENDING)\n  first_name       String?\n  last_name        String?\n  photo_url        String?\n  gender           Gender?\n  dob_encrypted    String?\n  class            String?\n  section          String?\n  roll_number      String?\n  admission_number String?\n  is_active        Boolean     @default(true)\n  created_at       DateTime    @default(now())\n  updated_at       DateTime    @updatedAt\n  deleted_at       DateTime?\n\n  // Pipeline tracking fields\n  card_number           String?         @unique\n  token                 String?         @unique\n  token_hash            String?         @unique\n  scan_url              String?\n  qr_code_url           String?\n  card_design_url       String?\n  pipeline_status       PipelineStatus? @default(PENDING)\n  pipeline_started_at   DateTime?\n  pipeline_completed_at DateTime?\n  design_status         DesignStatus?   @default(PENDING)\n  design_started_at     DateTime?\n  design_completed_at   DateTime?\n\n  // Relations\n  cards           Card[]\n  cardRenewals    CardRenewal[]\n  cardVisibility  CardVisibility?\n  editLogs        ParentEditLog[]\n  emergency       EmergencyProfile?\n  locationConsent LocationConsent?\n  locationEvents  LocationEvent[]\n  notifications   Notification[]\n  parents         ParentStudent[]\n  school          School?           @relation(fields: [school_id], references: [id], onDelete: SetNull)\n  tokens          Token[]\n  scanLogs        ScanLog[] // ADDED: opposite of ScanLog.student\n  orderItems      CardOrderItem[]\n\n  @@index([school_id])\n  @@index([setup_stage])\n  @@index([pipeline_status])\n  @@index([card_number])\n  @@index([token_hash])\n}\n\nmodel ParentStudent {\n  id           String     @id @default(uuid())\n  parent_id    String\n  student_id   String\n  relationship String?\n  is_primary   Boolean    @default(false)\n  created_at   DateTime   @default(now())\n  parent       ParentUser @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n  student      Student    @relation(fields: [student_id], references: [id], onDelete: Cascade)\n\n  @@unique([parent_id, student_id])\n}\n\nmodel EmergencyProfile {\n  id                     String             @id @default(uuid())\n  student_id             String             @unique\n  blood_group            BloodGroup?\n  allergies              String?\n  conditions             String?\n  medications            String?\n  doctor_name            String?\n  doctor_phone_encrypted String?\n  notes                  String?\n  visibility             ProfileVisibility  @default(PUBLIC)\n  is_visible             Boolean            @default(true)\n  created_at             DateTime           @default(now())\n  updated_at             DateTime           @updatedAt\n  contacts               EmergencyContact[]\n  student                Student            @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\nmodel EmergencyContact {\n  id               String           @id @default(uuid())\n  profile_id       String\n  name             String\n  phone_encrypted  String\n  relationship     String?\n  priority         Int\n  display_order    Int              @default(0)\n  is_active        Boolean          @default(true)\n  call_enabled     Boolean          @default(true)\n  whatsapp_enabled Boolean          @default(true)\n  created_at       DateTime         @default(now())\n  updated_at       DateTime         @updatedAt\n  profile          EmergencyProfile @relation(fields: [profile_id], references: [id], onDelete: Cascade)\n\n  @@unique([profile_id, priority])\n  @@index([profile_id])\n}\n\nmodel CardVisibility {\n  id                String            @id @default(uuid())\n  student_id        String            @unique\n  visibility        ProfileVisibility @default(PUBLIC)\n  hidden_fields     String[]          @default([])\n  updated_by_parent Boolean           @default(false)\n  created_at        DateTime          @default(now())\n  updated_at        DateTime          @updatedAt\n  student           Student           @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\nmodel ParentEditLog {\n  id          String         @id @default(uuid())\n  school_id   String?\n  student_id  String\n  parent_id   String\n  field_group ParentEditType\n  old_value   Json?\n  new_value   Json\n  ip_address  String?\n  user_agent  String?\n  created_at  DateTime       @default(now())\n  school      School?        @relation(fields: [school_id], references: [id], onDelete: SetNull)\n  student     Student        @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  parent      ParentUser     @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n\n  @@index([student_id])\n  @@index([parent_id])\n  @@index([created_at])\n}\n\n// =============================================================================\n// TOKENS & QR\n// =============================================================================\n\nmodel Token {\n  id             String      @id @default(uuid())\n  school_id      String\n  student_id     String?\n  token_hash     String      @unique\n  status         TokenStatus @default(UNASSIGNED)\n  batch_id       String?\n  order_id       String?\n  order_item_id  String?     @unique\n  replaced_by_id String?\n  activated_at   DateTime?\n  assigned_at    DateTime?\n  expires_at     DateTime?\n  revoked_at     DateTime?\n  created_at     DateTime    @default(now())\n\n  // Relations\n  orderItem    CardOrderItem? @relation(fields: [order_item_id], references: [id])\n  order        CardOrder?     @relation(fields: [order_id], references: [id])\n  batch        TokenBatch?    @relation(fields: [batch_id], references: [id])\n  school       School         @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student      Student?       @relation(fields: [student_id], references: [id], onDelete: SetNull)\n  replacedBy   Token?         @relation(\"TokenReplacement\", fields: [replaced_by_id], references: [id])\n  replacements Token[]        @relation(\"TokenReplacement\")\n\n  cards       Card[]\n  anomalies   ScanAnomaly[]\n  locations   LocationEvent[]\n  nonces      RegistrationNonce[]\n  scans       ScanLog[]\n  qrAsset     QrAsset?\n  is_honeypot Boolean             @default(false)\n\n  @@index([is_honeypot])\n  @@index([school_id, status])\n  @@index([order_id])\n  @@index([token_hash])\n  @@index([student_id])\n}\n\nmodel TokenBatch {\n  id              String           @id @default(uuid())\n  school_id       String\n  order_id        String?\n  count           Int\n  generated_count Int              @default(0)\n  failed_count    Int              @default(0)\n  status          TokenBatchStatus @default(PENDING)\n  created_by      String\n  notes           String?\n  completed_at    DateTime?\n  error_log       Json?\n  created_at      DateTime         @default(now())\n  updated_at      DateTime         @updatedAt\n  order           CardOrder?       @relation(fields: [order_id], references: [id])\n  tokens          Token[]\n  school          School           @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([order_id])\n  @@index([status])\n}\n\nmodel QrAsset {\n  id           String     @id @default(uuid())\n  token_id     String     @unique\n  school_id    String\n  storage_key  String     @unique\n  public_url   String\n  format       QrFormat   @default(PNG)\n  width_px     Int        @default(512)\n  height_px    Int        @default(512)\n  file_size_kb Int?\n  qr_type      QrType\n  generated_by String\n  order_id     String?\n  is_active    Boolean    @default(true)\n  generated_at DateTime   @default(now())\n  token        Token      @relation(fields: [token_id], references: [id], onDelete: Cascade)\n  order        CardOrder? @relation(fields: [order_id], references: [id])\n  school       School     @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id])\n  @@index([order_id])\n}\n\n// =============================================================================\n// CARD ORDER SYSTEM\n// =============================================================================\n\nmodel CardOrder {\n  id              String        @id @default(uuid())\n  school_id       String\n  subscription_id String?\n  order_number    String        @unique\n  order_type      OrderType\n  student_count   Int\n  status          OrderStatus   @default(PENDING)\n  order_channel   OrderChannel?\n\n  // Financial denorm\n  unit_price     Int?\n  grand_total    Int?\n  advance_amount Int?\n  balance_amount Int?\n\n  // Payment tracking\n  payment_status  OrderPaymentStatus @default(UNPAID)\n  advance_paid_at DateTime?\n  balance_paid_at DateTime?\n\n  // Pipeline progress tracking\n  pipeline_completed_count Int @default(0)\n  design_completed_count   Int @default(0)\n\n  // [H5] NEW: Timestamps for stalled job detection\n  pipeline_started_at DateTime?\n  design_started_at   DateTime?\n\n  // Invoice tracking\n  partial_invoice_id String? @unique\n  final_invoice_id   String? @unique\n\n  partialInvoice Invoice? @relation(\"PartialInvoiceForOrder\", fields: [partial_invoice_id], references: [id])\n  finalInvoice   Invoice? @relation(\"FinalInvoiceForOrder\", fields: [final_invoice_id], references: [id])\n\n  // Direct payments\n  payments Payment[]\n\n  // Delivery address\n  delivery_name    String?\n  delivery_phone   String?\n  delivery_address String?\n  delivery_city    String?\n  delivery_state   String?\n  delivery_pincode String?\n\n  // Audit\n  confirmed_by            String?\n  confirmed_at            DateTime?\n  tokens_generated_by     String?\n  tokens_generated_at     DateTime?\n  card_design_files       Json?\n  card_design_by          String?\n  card_design_at          DateTime?\n  vendor_id               String?\n  vendor_notes            String?\n  files_sent_to_vendor_at DateTime?\n  files_sent_by           String?\n  print_complete_at       DateTime?\n  print_complete_noted_by String?\n  status_changed_by       String?\n  status_changed_at       DateTime?\n  status_note             String?\n  notes                   String?\n  admin_notes             String?\n  caller_name             String?\n  caller_phone            String?\n  call_notes              String?\n\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n\n  // Relations\n  items                  CardOrderItem[]\n  qrAssets               QrAsset[]\n  shipment               OrderShipment?\n  cards                  Card[]\n  statusLogs             OrderStatusLog[]\n  tokens                 Token[]\n  tokenBatches           TokenBatch[]\n  pipeline               OrderPipeline?\n  vendor                 VendorProfile?          @relation(fields: [vendor_id], references: [id])\n  school                 School                  @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  subscription           Subscription?           @relation(fields: [subscription_id], references: [id])\n  invoices               Invoice[]\n  dashboardNotifications DashboardNotification[]\n\n  @@index([school_id])\n  @@index([status])\n  @@index([payment_status])\n  @@index([created_at])\n}\n\nmodel CardOrderItem {\n  id              String          @id @default(uuid())\n  order_id        String\n  student_id      String?\n  token_id        String?         @unique\n  student_name    String\n  class           String?\n  section         String?\n  roll_number     String?\n  photo_url       String?\n  status          OrderItemStatus @default(PENDING)\n  // [L1] FIXED: Replaced qr_generated Boolean with pipeline_status enum\n  pipeline_status PipelineStatus  @default(PENDING)\n  card_design_url String?\n  card_printed    Boolean         @default(false)\n  has_issue       Boolean         @default(false)\n  issue_note      String?\n  created_at      DateTime        @default(now())\n  updated_at      DateTime        @updatedAt\n  order           CardOrder       @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  token           Token?          @relation\n  student         Student?        @relation(fields: [student_id], references: [id])\n\n  @@index([order_id])\n  @@index([student_id])\n}\n\nmodel OrderStatusLog {\n  id          String       @id @default(uuid())\n  order_id    String\n  from_status OrderStatus?\n  to_status   OrderStatus\n  changed_by  String\n  // [M4] NEW: Actor type for audit trail\n  actor_type  ActorType    @default(SYSTEM)\n  note        String?\n  metadata    Json?\n  created_at  DateTime     @default(now())\n  order       CardOrder    @relation(fields: [order_id], references: [id], onDelete: Cascade)\n\n  @@index([order_id, created_at])\n}\n\nmodel OrderShipment {\n  id                     String            @id @default(uuid())\n  order_id               String            @unique\n  shiprocket_order_id    String?\n  shiprocket_shipment_id String?\n  awb_code               String?           @unique\n  courier_name           String?\n  courier_id             Int?\n  tracking_url           String?\n  label_url              String?\n  manifest_url           String?\n  pickup_vendor_id       String?\n  pickup_name            String?\n  pickup_contact         String?\n  pickup_address         String?\n  pickup_city            String?\n  pickup_state           String?\n  pickup_pincode         String?\n  delivery_name          String?\n  delivery_phone         String?\n  delivery_address       String?\n  delivery_city          String?\n  delivery_state         String?\n  delivery_pincode       String?\n  status                 ShipmentStatus    @default(PENDING)\n  shiprocket_status      ShiprocketStatus?\n  created_by             String?\n  tracking_shared_at     DateTime?\n  tracking_shared_by     String?\n  pickup_scheduled_at    DateTime?\n  picked_up_at           DateTime?\n  estimated_delivery_at  DateTime?\n  delivered_at           DateTime?\n  delivery_confirmed_by  String?\n  notes                  String?\n  created_at             DateTime          @default(now())\n  updated_at             DateTime          @updatedAt\n  order                  CardOrder         @relation(fields: [order_id], references: [id], onDelete: Cascade)\n\n  @@index([status])\n  @@index([awb_code])\n}\n\nmodel VendorProfile {\n  id                  String       @id @default(uuid())\n  name                String\n  contact_name        String?\n  phone               String?\n  email               String?\n  status              VendorStatus @default(ACTIVE)\n  address             String?\n  city                String?\n  state               String?\n  pincode             String?\n  gstin               String?\n  speciality          String?\n  avg_turnaround_days Int?\n  notes               String?\n  created_at          DateTime     @default(now())\n  updated_at          DateTime     @updatedAt\n  orders              CardOrder[]\n\n  @@index([status])\n}\n\nmodel Card {\n  id           String        @id @default(uuid())\n  school_id    String\n  student_id   String?\n  token_id     String?\n  order_id     String?\n  card_number  String        @unique\n  file_url     String?\n  print_status PrintStatus   @default(PENDING)\n  printed_at   DateTime?\n  created_at   DateTime      @default(now())\n  renewals     CardRenewal[]\n  school       School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student      Student?      @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  token        Token?        @relation(fields: [token_id], references: [id])\n  order        CardOrder?    @relation(fields: [order_id], references: [id])\n\n  @@index([school_id])\n  @@index([token_id])\n  @@index([order_id])\n  @@index([card_number])\n}\n\nmodel CardRenewal {\n  id           String       @id @default(uuid())\n  card_id      String\n  student_id   String\n  school_id    String\n  renewed_by   String?\n  renewer_type ActorType    @default(PARENT_USER)\n  old_expiry   DateTime\n  new_expiry   DateTime\n  amount_paid  Int\n  tax_amount   Int          @default(0)\n  payment_id   String?\n  school_type  SchoolType?\n  pricing_tier PricingTier?\n  created_at   DateTime     @default(now())\n  card         Card         @relation(fields: [card_id], references: [id], onDelete: Cascade)\n  payment      Payment?     @relation(\"RenewalPayment\", fields: [payment_id], references: [id])\n  school       School       @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student      Student      @relation(fields: [student_id], references: [id], onDelete: Cascade)\n\n  @@index([card_id])\n  @@index([student_id])\n}\n\n// =============================================================================\n// MONEY (UPDATED Invoice)\n// =============================================================================\n\nmodel Subscription {\n  id                   String             @id @default(uuid())\n  school_id            String\n  plan                 PlanType           @default(GOVT_STANDARD)\n  status               SubscriptionStatus @default(TRIALING)\n  pricing_tier         PricingTier        @default(PRIVATE_STANDARD)\n  student_count        Int                @default(0)\n  unit_price           Int                @default(19900)\n  grand_total          Int                @default(0)\n  current_period_start DateTime\n  current_period_end   DateTime\n  trial_ends_at        DateTime?\n  fully_paid_at        DateTime?\n  created_at           DateTime           @default(now())\n  updated_at           DateTime           @updatedAt\n  cardOrders           CardOrder[]\n  school               School             @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  invoices             Invoice[]\n\n  @@index([school_id])\n  @@index([status])\n}\n\nmodel Invoice {\n  id              String  @id @default(uuid())\n  school_id       String\n  order_id        String?\n  subscription_id String?\n\n  // Invoice categorization\n  category             InvoiceCategory\n  order_invoice_type   OrderInvoiceType?\n  renewal_invoice_type RenewalInvoiceType?\n\n  invoice_number   String        @unique\n  student_count    Int\n  unit_price       Int\n  amount           Int\n  tax_amount       Int\n  total_amount     Int\n  status           InvoiceStatus @default(ISSUED)\n  issued_at        DateTime      @default(now())\n  due_at           DateTime?\n  paid_at          DateTime?\n  pdf_url          String?\n  // [H3] NEW: PDF generation timestamp for idempotency\n  pdf_generated_at DateTime?\n\n  // Relations\n  order        CardOrder?    @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  subscription Subscription? @relation(fields: [subscription_id], references: [id], onDelete: SetNull)\n  payments     Payment[]\n  school       School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  // Reverse relations for CardOrder's partial/final invoices\n  partialOrder CardOrder? @relation(\"PartialInvoiceForOrder\")\n  finalOrder   CardOrder? @relation(\"FinalInvoiceForOrder\")\n\n  @@index([order_id])\n  @@index([category, order_invoice_type])\n  @@index([status])\n  @@index([invoice_number])\n}\n\nmodel Payment {\n  id              String        @id @default(uuid())\n  school_id       String\n  order_id        String\n  invoice_id      String?\n  subscription_id String?\n  amount          Int\n  status          PaymentStatus @default(SUCCESS)\n  // [M3] REMOVED: provider field (offline payments don't have a provider)\n  payment_mode    PaymentMode   @default(BANK_TRANSFER)\n  is_advance      Boolean       @default(true)\n  metadata        Json?\n  created_at      DateTime      @default(now())\n  order           CardOrder     @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  invoice         Invoice?      @relation(fields: [invoice_id], references: [id])\n  school          School        @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  renewals        CardRenewal[] @relation(\"RenewalPayment\")\n\n  @@index([order_id])\n  @@index([invoice_id])\n  @@index([created_at])\n}\n\n// =============================================================================\n// DASHBOARD NOTIFICATIONS (UPDATED)\n// =============================================================================\n\nmodel DashboardNotification {\n  id         String                    @id @default(uuid())\n  user_id    String\n  // [C2] FIXED: Changed from String to enum\n  user_type  DashboardUserType\n  type       DashboardNotificationType\n  title      String\n  body       String\n  metadata   Json?\n  read       Boolean                   @default(false)\n  read_at    DateTime?\n  created_at DateTime                  @default(now())\n\n  school_id String?\n  order_id  String?\n\n  // [H1] NEW: Typed FK relations to SchoolUser and SuperAdmin\n  school_user_id String?\n  super_admin_id String?\n\n  school     School?     @relation(fields: [school_id], references: [id], onDelete: SetNull)\n  order      CardOrder?  @relation(fields: [order_id], references: [id], onDelete: SetNull)\n  schoolUser SchoolUser? @relation(fields: [school_user_id], references: [id], onDelete: Cascade)\n  superAdmin SuperAdmin? @relation(fields: [super_admin_id], references: [id], onDelete: Cascade)\n\n  // [M5] NEW: Composite index for efficient queries\n  @@index([user_id, user_type])\n  @@index([user_id, read])\n  @@index([user_id, created_at])\n  @@index([type, created_at])\n  @@index([school_id])\n}\n\n// =============================================================================\n// SCAN LOGS (UPDATED)\n// =============================================================================\n\nmodel ScanLog {\n  id               String         @id @default(uuid())\n  token_id         String\n  student_id       String?\n  school_id        String\n  result           ScanResult\n  scan_type        ScanType       @default(OTHER)\n  scanned_by       String?\n  scanned_at       DateTime       @default(now())\n  ip_address       String?\n  ip_city          String?\n  ip_country       String?\n  ip_region        String?\n  ip_capture_basis IpCaptureBasis @default(LEGITIMATE_INTEREST)\n  location_derived Boolean        @default(true)\n  latitude         Float?\n  longitude        Float?\n  device_hash      String?\n  device_info      Json?\n  user_agent       String?\n  scan_purpose     ScanPurpose    @default(QR_SCAN)\n  response_time_ms Int?\n\n  emergency_dispatched Boolean   @default(false)\n  dispatched_at        DateTime?\n\n  // [M1] NEW: Track per-channel delivery status\n  dispatched_channels String[] @default([])\n  failed_channels     String[] @default([])\n\n  created_at DateTime @default(now())\n\n  // Relations - SINGLE definition of student\n  token   Token    @relation(fields: [token_id], references: [id], onDelete: Cascade)\n  student Student? @relation(fields: [student_id], references: [id], onDelete: SetNull)\n  school  School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id, created_at])\n  @@index([student_id, created_at])\n  @@index([school_id, created_at])\n  @@index([school_id, result])\n  @@index([scan_type, created_at])\n  @@index([emergency_dispatched, dispatched_at])\n}\n\nmodel ScanAnomaly {\n  id           String          @id @default(uuid())\n  token_id     String\n  anomaly_type AnomalyType\n  severity     AnomalySeverity @default(MEDIUM)\n  reason       String?\n  metadata     Json?\n  resolved     Boolean         @default(false)\n  resolved_at  DateTime?\n  resolved_by  String?\n  created_at   DateTime        @default(now())\n  token        Token           @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id])\n  @@index([anomaly_type])\n}\n\nmodel ScanRateLimit {\n  id              String                  @id @default(uuid())\n  identifier      String\n  identifier_type RateLimitIdentifierType\n  count           Int                     @default(1)\n  window_start    DateTime                @default(now())\n  last_hit        DateTime                @default(now())\n  blocked_until   DateTime?\n  blocked_reason  String?\n  block_count     Int                     @default(0)\n\n  @@unique([identifier, identifier_type])\n  @@index([blocked_until])\n}\n\n// =============================================================================\n// LOCATION\n// =============================================================================\n\nmodel LocationConsent {\n  id           String   @id @default(uuid())\n  student_id   String   @unique\n  enabled      Boolean  @default(false)\n  consented_by String?\n  consent_text String?\n  ip_address   String?\n  created_at   DateTime @default(now())\n  updated_at   DateTime @updatedAt\n  student      Student  @relation(fields: [student_id], references: [id], onDelete: Cascade)\n}\n\nmodel LocationEvent {\n  id         String         @id @default(uuid())\n  student_id String\n  school_id  String\n  token_id   String?\n  latitude   Float\n  longitude  Float\n  accuracy   Float?\n  altitude   Float?\n  source     LocationSource @default(SCAN_TRIGGER)\n  created_at DateTime       @default(now())\n  student    Student        @relation(fields: [student_id], references: [id], onDelete: Cascade)\n  school     School         @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  token      Token?         @relation(fields: [token_id], references: [id])\n\n  @@index([student_id, created_at])\n  @@index([school_id, created_at])\n}\n\nmodel RegistrationNonce {\n  id          String    @id @default(uuid())\n  nonce       String    @unique\n  token_id    String\n  phone_index String?\n  expires_at  DateTime\n  used        Boolean   @default(false)\n  used_at     DateTime?\n  created_at  DateTime  @default(now())\n  token       Token     @relation(fields: [token_id], references: [id], onDelete: Cascade)\n\n  @@index([token_id])\n  @@index([expires_at])\n}\n\nmodel TrustedScanZone {\n  id         String   @id @default(uuid())\n  school_id  String\n  label      String\n  ip_range   String?\n  latitude   Float?\n  longitude  Float?\n  radius_m   Int      @default(200)\n  is_active  Boolean  @default(true)\n  created_by String?\n  updated_by String?\n  created_at DateTime @default(now())\n  updated_at DateTime @updatedAt\n  school     School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id, is_active])\n}\n\n// =============================================================================\n// EXTERNAL NOTIFICATIONS\n// =============================================================================\n\nmodel Notification {\n  id          String              @id @default(uuid())\n  school_id   String\n  student_id  String?\n  parent_id   String?\n  type        String\n  channel     NotificationChannel\n  status      NotificationStatus  @default(QUEUED)\n  recipient   String\n  subject     String?\n  content     String?\n  payload     Json?\n  retry_count Int                 @default(0)\n  sent_at     DateTime?\n  error       String?\n  created_at  DateTime            @default(now())\n  school      School              @relation(fields: [school_id], references: [id], onDelete: Cascade)\n  student     Student?            @relation(fields: [student_id], references: [id])\n  parent      ParentUser?         @relation(fields: [parent_id], references: [id])\n\n  @@index([school_id])\n  @@index([status, created_at])\n  @@index([channel, status])\n}\n\n// =============================================================================\n// AUDIT LOG\n// =============================================================================\n\nmodel AuditLog {\n  id         String    @id @default(uuid())\n  school_id  String?\n  actor_id   String\n  actor_type ActorType\n  action     String\n  entity     String\n  entity_id  String\n  old_value  Json?\n  new_value  Json?\n  metadata   Json?\n  ip_address String?\n  user_agent String?\n  created_at DateTime  @default(now())\n  school     School?   @relation(fields: [school_id], references: [id])\n\n  @@index([actor_id])\n  @@index([school_id])\n  @@index([entity, entity_id])\n  @@index([created_at])\n}\n\n// =============================================================================\n// API KEYS & WEBHOOKS\n// =============================================================================\n\nmodel ApiKey {\n  id           String    @id @default(uuid())\n  school_id    String\n  name         String\n  key_hash     String    @unique\n  key_prefix   String\n  scopes       String[]\n  last_used_at DateTime?\n  expires_at   DateTime?\n  revoked_at   DateTime?\n  created_at   DateTime  @default(now())\n  school       School    @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id])\n}\n\nmodel Webhook {\n  id          String            @id @default(uuid())\n  school_id   String\n  url         String\n  secret_hash String\n  events      String[]\n  is_active   Boolean           @default(true)\n  created_at  DateTime          @default(now())\n  deliveries  WebhookDelivery[]\n  school      School            @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@index([school_id, is_active])\n}\n\nmodel WebhookDelivery {\n  id              String    @id @default(uuid())\n  webhook_id      String\n  idempotency_key String?   @unique\n  event_type      String\n  payload         Json\n  status_code     Int?\n  response        String?\n  attempt         Int       @default(1)\n  delivered_at    DateTime?\n  created_at      DateTime  @default(now())\n  webhook         Webhook   @relation(fields: [webhook_id], references: [id], onDelete: Cascade)\n\n  @@index([webhook_id, created_at])\n}\n\nmodel WebhookEvent {\n  id           String    @id @default(uuid())\n  provider     String\n  event_type   String\n  payload      Json\n  received_at  DateTime  @default(now())\n  processed    Boolean   @default(false)\n  processed_at DateTime?\n  error        String?\n\n  @@index([provider, event_type])\n  @@index([processed])\n}\n\n// =============================================================================\n// OPERATIONS & RESILIENCE\n// =============================================================================\n\nmodel DeadLetterQueue {\n  id            String    @id @default(uuid())\n  job_type      String\n  payload       Json\n  error_message String\n  retry_count   Int       @default(0)\n  last_attempt  DateTime  @default(now())\n  resolved      Boolean   @default(false)\n  resolved_at   DateTime?\n  created_at    DateTime  @default(now())\n\n  @@index([job_type, resolved])\n}\n\nmodel IdempotencyKey {\n  id            String   @id @default(uuid())\n  key           String   @unique\n  resource_type String\n  resource_id   String\n  status        String\n  response      Json?\n  expires_at    DateTime\n  created_at    DateTime @default(now())\n\n  @@index([expires_at])\n}\n\nmodel FeatureFlagOverride {\n  id          String    @id @default(uuid())\n  flag_key    String\n  target_type String\n  target_id   String\n  enabled     Boolean\n  percentage  Int?\n  expires_at  DateTime?\n  created_by  String\n  created_at  DateTime  @default(now())\n  updated_at  DateTime  @updatedAt\n\n  @@unique([flag_key, target_type, target_id])\n  @@index([flag_key])\n}\n\n// =============================================================================\n// SECURITY & ABUSE PREVENTION\n// =============================================================================\n\nmodel AuthAttempt {\n  id              String   @id @default(uuid())\n  identifier      String\n  identifier_type String\n  success         Boolean  @default(false)\n  failure_reason  String?\n  ip_address      String?\n  user_agent      String?\n  created_at      DateTime @default(now())\n\n  @@index([identifier, created_at])\n  @@index([ip_address, created_at])\n}\n\nmodel IpBlocklist {\n  id         String    @id @default(uuid())\n  ip_address String    @unique\n  reason     String\n  blocked_by String\n  blocked_at DateTime  @default(now())\n  expires_at DateTime?\n  is_active  Boolean   @default(true)\n\n  @@index([ip_address, is_active])\n  @@index([expires_at])\n}\n\n// =============================================================================\n// PIPELINE MODELS\n// =============================================================================\n\nmodel OrderPipeline {\n  id               String               @id @default(uuid())\n  order_id         String               @unique\n  current_step     PipelineStepName\n  overall_progress Int                  @default(0)\n  is_stalled       Boolean              @default(false)\n  stalled_at       DateTime?\n  stalled_reason   String?\n  started_at       DateTime             @default(now())\n  completed_at     DateTime?\n  updated_at       DateTime             @updatedAt\n  order            CardOrder            @relation(fields: [order_id], references: [id], onDelete: Cascade)\n  steps            OrderStepExecution[]\n\n  @@index([order_id])\n  @@index([current_step])\n  @@index([is_stalled])\n}\n\nmodel OrderStepExecution {\n  id              String           @id @default(uuid())\n  pipeline_id     String\n  order_id        String\n  step            PipelineStepName\n  attempt_number  Int              @default(1)\n  status          StepStatus       @default(PENDING)\n  started_at      DateTime?\n  completed_at    DateTime?\n  duration_ms     Int?\n  progress        Int              @default(0)\n  progress_detail Json?\n  result_summary  Json?\n  error_log       Json?\n  triggered_by    String\n  triggered_at    DateTime         @default(now())\n  pipeline        OrderPipeline    @relation(fields: [pipeline_id], references: [id], onDelete: Cascade)\n  jobs            JobExecution[]\n  logs            StepLog[]\n\n  @@unique([pipeline_id, step, attempt_number])\n  @@index([pipeline_id])\n  @@index([order_id])\n  @@index([step, status])\n}\n\nmodel JobExecution {\n  id                String             @id @default(uuid())\n  step_execution_id String\n  order_id          String\n  queue_name        String\n  bullmq_job_id     String?\n  job_name          String\n  status            JobStatus          @default(QUEUED)\n  payload           Json\n  queued_at         DateTime           @default(now())\n  started_at        DateTime?\n  completed_at      DateTime?\n  duration_ms       Int?\n  progress          Int                @default(0)\n  attempt_number    Int                @default(1)\n  max_attempts      Int                @default(3)\n  last_error        String?\n  error_log         Json?\n  result            Json?\n  stepExecution     OrderStepExecution @relation(fields: [step_execution_id], references: [id], onDelete: Cascade)\n\n  @@index([step_execution_id])\n  @@index([order_id])\n  @@index([queue_name, status])\n}\n\nmodel StepLog {\n  id                String             @id @default(uuid())\n  step_execution_id String\n  order_id          String\n  job_execution_id  String?\n  level             String\n  message           String\n  context           Json?\n  created_at        DateTime           @default(now())\n  stepExecution     OrderStepExecution @relation(fields: [step_execution_id], references: [id], onDelete: Cascade)\n\n  @@index([step_execution_id])\n  @@index([order_id, created_at])\n  @@index([level, created_at])\n}\n\n// =============================================================================\n// FEATURE FLAGS & TEMPLATES\n// =============================================================================\n\nmodel FeatureFlag {\n  id          String   @id @default(uuid())\n  key         String   @unique\n  enabled     Boolean  @default(false)\n  description String?\n  metadata    Json?\n  updated_at  DateTime @updatedAt\n}\n\nmodel SchoolFeatureFlag {\n  id         String   @id @default(uuid())\n  school_id  String\n  key        String\n  enabled    Boolean\n  updated_at DateTime @updatedAt\n  school     School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n\n  @@unique([school_id, key])\n  @@index([school_id])\n}\n\nmodel CardTemplate {\n  id                 String   @id @default(uuid())\n  school_id          String   @unique\n  logo_url           String?\n  background_color   String   @default(\"#FFFFFF\")\n  primary_color      String   @default(\"#000000\")\n  text_color         String   @default(\"#000000\")\n  qr_dark_color      String   @default(\"#000000\")\n  qr_light_color     String   @default(\"#FFFFFF\")\n  cover_accent_color String   @default(\"#E8342A\")\n  cover_tagline      String?\n  cards_per_sheet    Int      @default(8)\n  card_width         Int      @default(640)\n  card_height        Int      @default(400)\n  show_student_name  Boolean  @default(true)\n  show_class         Boolean  @default(true)\n  show_school_name   Boolean  @default(true)\n  show_photo         Boolean  @default(true)\n  is_locked          Boolean  @default(true)\n  updated_by         String?\n  created_at         DateTime @default(now())\n  updated_at         DateTime @updatedAt\n  school             School   @relation(fields: [school_id], references: [id], onDelete: Cascade)\n}\n\n// =============================================================================\n// SESSIONS\n// =============================================================================\n\nmodel Session {\n  id                 String               @id @default(uuid())\n  parent_user_id     String?\n  school_user_id     String?\n  admin_user_id      String?\n  refresh_token_hash String               @unique\n  device_id          String?\n  device_info        String?\n  user_agent         String?\n  ip_address         String?\n  is_active          Boolean              @default(true)\n  revoked_at         DateTime?\n  revoke_reason      SessionRevokeReason?\n  last_active_at     DateTime?\n  expires_at         DateTime\n  created_at         DateTime             @default(now())\n  parentUser         ParentUser?          @relation(fields: [parent_user_id], references: [id], onDelete: Cascade)\n  schoolUser         SchoolUser?          @relation(fields: [school_user_id], references: [id], onDelete: Cascade)\n  superAdmin         SuperAdmin?          @relation(fields: [admin_user_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_user_id, is_active])\n  @@index([school_user_id, is_active])\n  @@index([admin_user_id])\n  @@index([expires_at])\n}\n\nmodel BlacklistToken {\n  token_hash String   @id\n  expires_at DateTime\n  created_at DateTime @default(now())\n\n  @@index([expires_at])\n}\n\nmodel DeviceLoginLog {\n  id            String         @id @default(uuid())\n  parent_id     String\n  device_name   String?\n  device_model  String?\n  platform      DevicePlatform\n  os_version    String?\n  app_version   String?\n  ip_address    String?\n  ip_city       String?\n  ip_country    String?\n  login_at      DateTime       @default(now())\n  email_sent    Boolean        @default(false)\n  email_sent_at DateTime?\n  was_forced    Boolean        @default(false)\n  parent        ParentUser     @relation(fields: [parent_id], references: [id], onDelete: Cascade)\n\n  @@index([parent_id, login_at])\n}\n"
}

